{{ $json.mensaje_lista }}

🔢 Escribe el número \(1\-5\) para ver el detalle, o *0* para el menú\.

parameters.jsCode:
const op = parseInt($('HelpDeskBot Trigger').first().json.message.text);
const tickets = $input.all().map(i => i.json).filter(t => t.id_ticket)
  .filter(t => {
    const e = (t.estado||'').toLowerCase();
    return e !== 'cerrado' && e !== 'cerrada';
  }).reverse().slice(0,5);
const sel = tickets[op-1];
if (!sel) {
  return [{ json: { error: true, id:'', tipo:'', prioridad:'', estado:'', descripcion:'',
    mensaje_error: '⚠️ Opción no válida. Escribe un número del 1 al ' + tickets.length + '.' } }];
}
return [{ json: { error: false, id: sel.id_ticket, tipo: sel.tipo,
  prioridad: sel.prioridad, estado: sel.estado, descripcion: sel.descripcion } }];

