const s = $input.all().map(i => i.json).filter(t => t.id_ticket);
let abiertas=0, proceso=0, cerradas=0;
s.forEach(t => {
  const e = (t.estado||'').toLowerCase();
  if (e==='abierto'||e==='abierta') abiertas++;
  else if (e==='en proceso') proceso++;
  else if (e==='cerrado'||e==='cerrada') cerradas++;
});
const total = s.length;
if (total===0) {
  return [{ json: { reporte: '📊 *Reporte de solicitudes*\n\nNo hay solicitudes registradas aún.' } }];
}
return [{ json: { reporte:
  '📊 *Reporte de solicitudes*\n\n' +
  '🟢 Abiertas: ' + abiertas + '\n' +
  '🟡 En proceso: ' + proceso + '\n' +
  '🔵 Cerradas: ' + cerradas + '\n' +
  '─────────────\n' +
  '📈 Total: ' + total
}}];
